import React, { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import { useDispatch, useSelector } from 'react-redux';
import { Phone, ArrowRight, Loader } from 'lucide-react';
import { authAPI } from '../services/api';
import {
  loginWithOtp,
  setOtpSent,
  clearError,
} from '../store/slices/authslice';

const LoginPage = () => {
  const navigate = useNavigate();
  const location = useLocation();
  const dispatch = useDispatch();
  const { loading, error, otpSent } = useSelector((state) => state.auth);

  const [phone, setPhone] = useState('');
  const [otp, setOtp] = useState('');
  const [sendingOtp, setSendingOtp] = useState(false);

  const from = location.state?.from?.pathname || '/';

  const handleSendOtp = async (e) => {
    e.preventDefault();
    if (!phone.match(/^[0-9]{10}$/)) return;

    setSendingOtp(true);
    try {
      await authAPI.sendOtp(phone);
      dispatch(setOtpSent(true));
      dispatch(clearError());
    } catch (err) {
      console.error(err);
    } finally {
      setSendingOtp(false);
    }
  };

  const handleVerify = async (e) => {
    e.preventDefault();
    const result = await dispatch(loginWithOtp({ phone, otp }));
    if (result.meta.requestStatus === 'fulfilled') {
      navigate(from, { replace: true });
    }
  };

  return (
    <div className="min-h-screen flex items-center justify-center bg-gray-50 px-4">
      <div className="w-full max-w-md bg-white rounded-2xl shadow-lg p-6 md:p-8">
        <div className="text-center mb-8">
          <h1 className="text-2xl font-bold text-gray-900">Welcome Back</h1>
          <p className="text-gray-500 mt-1">Login with your phone number</p>
        </div>

        {!otpSent ? (
          <form onSubmit={handleSendOtp} className="space-y-4">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Phone Number
              </label>
              <div className="relative">
                <span className="absolute left-3 top-2.5 text-gray-500 font-medium">
                  +91
                </span>
                <input
                  type="tel"
                  placeholder="9876543210"
                  maxLength={10}
                  className="w-full pl-12 pr-4 py-2.5 border border-gray-200 rounded-lg focus:ring-2 focus:ring-primary-500"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value.replace(/\D/g, ''))}
                  required
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={sendingOtp || phone.length !== 10}
              className="w-full bg-primary-700 text-white py-2.5 rounded-lg font-medium hover:bg-primary-800 transition flex items-center justify-center gap-2 disabled:opacity-70"
            >
              {sendingOtp ? (
                <Loader className="w-4 h-4 animate-spin" />
              ) : (
                <>
                  Send OTP
                  <ArrowRight className="w-4 h-4" />
                </>
              )}
            </button>
          </form>
        ) : (
          <form onSubmit={handleVerify} className="space-y-4">
            <div className="text-center mb-4">
              <p className="text-sm text-gray-600">OTP sent to +91 {phone}</p>
              <button
                type="button"
                onClick={() => dispatch(setOtpSent(false))}
                className="text-sm text-primary-600 mt-1 hover:underline"
              >
                Change number
              </button>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Enter OTP
              </label>
              <input
                type="text"
                placeholder="123456"
                maxLength={6}
                className="w-full px-4 py-2.5 border border-gray-200 rounded-lg text-center text-2xl tracking-[0.5em] font-bold focus:ring-2 focus:ring-primary-500"
                value={otp}
                onChange={(e) => setOtp(e.target.value.replace(/\D/g, ''))}
                required
              />
            </div>

            {error && (
              <p className="text-sm text-red-600 text-center">{error}</p>
            )}

            <button
              type="submit"
              disabled={loading || otp.length !== 6}
              className="w-full bg-primary-700 text-white py-2.5 rounded-lg font-medium hover:bg-primary-800 transition disabled:opacity-70"
            >
              {loading ? (
                <Loader className="w-4 h-4 animate-spin mx-auto" />
              ) : (
                'Verify & Login'
              )}
            </button>

            <button
              type="button"
              onClick={handleSendOtp}
              className="w-full text-sm text-primary-600 hover:underline"
            >
              Resend OTP
            </button>
          </form>
        )}

        <p className="text-xs text-gray-500 text-center mt-6">
          By continuing, you agree to our Terms of Service and Privacy Policy
        </p>
      </div>
    </div>
  );
};

export default LoginPage;
